  if (!resumed) {
        const lastTime = localStorage.getItem('lastTime_myVideo');
        if (lastTime) {
          setTimeout(() => {
            player.currentTime(lastTime);
          }, 50);
        }
        resumed = true; // מסמן ששחזור בוצע
