		if (typeof video_vimeoid !== "undefined" || video_vimeoid) {
			video.getCurrentTime().then(function(data) {
			var currenttime = data;
			theform[0][0].value = currenttime;
			$('#bookmark-position-6a36e6133effa6a36e613290a68').val(currenttime);
			$('#bookmark-position-visible-6a36e6133effa6a36e613290a68').val(s_to_hms(currenttime));
				});
		} else {
			var currenttime = video.currentTime;
			theform[0][0].value = currenttime;
			$('#bookmark-position-6a36e6133effa6a36e613290a68').val(currenttime);
			$('#bookmark-position-visible-6a36e6133effa6a36e613290a68').val(s_to_hms(currenttime));
		}		
		
		var checkBox = $('#teacherbookmark');
		if (checkBox.is(':checked')) {
			  $("#teacherbookmark").val("1");
		} 
	
		$.ajax({
            type: "POST",
            url: M.cfg.wwwroot + '/lib/ajax/service.php?sesskey=TXKW0C9OJa&info=local_video_directory_save_bookmark',
            data: JSON.stringify([{
                "index": 0,
                "methodname": "local_video_directory_save_bookmark",
                "args": {'videoid': 439903, 
						 'time': Math.round(currenttime), 
						 'userid': 102628, 
						 'cmid': 1182239,
						 'courseid': 65444,
						 'bookmarkname': $('#bookmarkname-6a36e6133effa6a36e613290a68').val(),
						 'isteacher': $("#teacherbookmark").val() }
            }])
        });
		var context = {
			bookmarkposition: Math.round(currenttime),
			bookmarkpositionvisible: s_to_hms(currenttime),
			bookmarkname: $('#bookmarkname-6a36e6133effa6a36e613290a68').val(),
			bookmarkflag: $('#bookmarkflagtoggle-6a36e6133effa6a36e613290a68').hasClass('flagged') ? 1 : 0,
			isteacher: $("#teacherbookmark").val("1") ? true : false
		};
		templates
				.render('local_video_directory/bookmark', context)
				.then(function(html, js) {
					templates.appendNodeContents('#videobookmarklist', html, js);
				}).fail(function(ex) {
					console.log(ex);
				});

	});
	
	$('#videobookmarklist').on('click', 'a', function(e) {
		if (typeof video_vimeoid !== "undefined" || video_vimeoid) {
            video.setCurrentTime($(this).data('position'));
		} else {
			video.currentTime = $(this).data('position');
		}
	});
	
	$('#videobookmarklist').on('click', '.deletebookmark', function(e) {
		if (!confirm('מחיקת סימניה')) {
			return;
		}
		var elem = $(this);

		$.ajax({
            type: "POST",
            url: M.cfg.wwwroot + '/lib/ajax/service.php?sesskey=TXKW0C9OJa&info=local_video_directory_save_bookmark',
            data: JSON.stringify([{
                "index": 0,
                "methodname": "local_video_directory_save_bookmark",
                "args": {'videoid': elem.data('id'), 
						 'time': 0, 
						 'userid': 0, 
						 'cmid': 0,
						 'courseid': 0,
						 'bookmarkname': 'deletebookmark',
						 'isteacher': 0 }
            }])
        });


		console.log($(this), $(this).closest('div'));
		elem.closest('div').hide(400, function () {elem.remove()});
	});
	
	function s_to_hms(totalSeconds) {
		hours = Math.floor(totalSeconds / 3600);
		if (hours < 10) {
			hours = '0' + hours;
		}
		totalSeconds %= 3600;
		minutes = Math.floor(totalSeconds / 60);
		if (minutes < 10) {
			minutes = '0' + minutes;
		}
		seconds = ~~(totalSeconds % 60);
		if (seconds < 10) {
			seconds = '0' + seconds;
		}
		return hours + ':' + minutes + ':' + seconds
	}
});
